.week-nav {
  display: flex;
  justify-content: center;
  align-items: center;
  margin: 0.5rem 0;
  gap: 1rem;
  color: #f0f0f0;
}

.week-nav button {
  background-color: #1f1f1f;
  color: #f0f0f0;
  border: 1px solid #444;
  padding: 6px 12px;
  border-radius: 6px;
  cursor: pointer;
  font-weight: bold;
  transition: all 0.2s;
}

.week-nav button:hover {
  background-color: #3b82f6;
  color: #fff;
  border-color: #2563eb;
}

.week-nav span {
  font-weight: bold;
  font-size: 0.9rem;
  background-color: #2a2a2a;
  padding: 4px 10px;
  border-radius: 6px;
  border: 1px solid #444;
}
